mapper.select:
/* SQL ID : SrvypprDAO.srvypprList 설 명 : 설문지목록 */ SELECT * FROM TB_LMS_SRVYPPR
WHERE SRVY_ID IN (SELECT SRVY_ID FROM TB_LMS_SRVY WHERE DELYN = 'N' AND USEYN = 'Y' AND (SRVY_ID = #{srvyId} OR UP_SRVY_ID = #{srvyId})) ORDER BY SRVY_ID, SRVY_SEQNO
WHERE SRVY_ID = #{srvyId} ORDER BY SRVY_SEQNO

mapper.delete:
		/*
             SQL ID : SrvypprDAO.srvypprDelete
             설  명  : 설문지삭제
         */
        DELETE FROM TB_LMS_SRVYPPR
         WHERE SRVYPPR_ID = #{srvypprId}

mapper.update:
		/*
             SQL ID : SrvypprDAO.srvypprDelNSeqnoModify
             설  명  : 설문지미삭제순번수정
         */
        UPDATE TB_LMS_SRVYPPR SET
        	  MDFR_ID = #{userId}
        	, MOD_DTTM = FN_DTTM()
        	, SRVY_SEQNO = SRVY_SEQNO - 1
         WHERE SRVY_ID = #{srvyId}
           AND SRVY_SEQNO  >  #{srvySeqno}
